import React, { useState } from 'react';
import { Box } from 'ink';
import { Tabs } from './navigation/Tabs.js';
import { Table } from './data/Table.js';
import { ProgressBar } from './feedback/ProgressBar.js';

export function DashboardRecipe() {
  const [activeTab, setActiveTab] = useState(0);

  const sampleData = [
    { name: 'Service A', status: 'running', uptime: '99.9%' },
    { name: 'Service B', status: 'degraded', uptime: '95.2%' },
  ];

  return (
    <Box flexDirection="column" gap={1}>
      <Tabs
        items={['Overview', 'Services', 'Logs']}
        activeIndex={activeTab}
        onChange={setActiveTab}
      />
      {activeTab === 0 && (
        <Box flexDirection="column" gap={1}>
          <ProgressBar value={72} total={100} label="CPU Usage" />
          <ProgressBar value={45} total={100} label="Memory" />
        </Box>
      )}
      {activeTab === 1 && (
        <Table
          data={sampleData}
          columns={[
            { key: 'name', header: 'Service' },
            { key: 'status', header: 'Status' },
            { key: 'uptime', header: 'Uptime' },
          ]}
        />
      )}
    </Box>
  );
}
